            Tags = """["leads","sales","reference"]""",
            ContentJson = """{"title":"Leads Field Reference","groups":[{"heading":"Lead Form Fields","items":[{"label":"Company Name (required)","value":"The prospect company. Can't be left blank. Becomes the customer name if you convert the lead."},{"label":"Contact Name","value":"Optional. The person you're working with at the company. If you fill it in, they become a contact on the customer when the lead converts."},{"label":"Email","value":"Optional. Must look like a real email address. Carried over to the customer and contact when the lead converts."},{"label":"Phone","value":"Optional. The contact's phone number. Carried over to the customer and contact when the lead converts."},{"label":"Source","value":"Optional. How the lead found you — for example Referral, Website, Trade Show, or Cold Call. Your admin sets the list of choices, and there's a blank option too."},{"label":"Follow-Up Date","value":"Optional. When you should next reach out. Turns red once the date has passed, as a reminder that it's overdue."},{"label":"Notes","value":"Optional. Free-form notes about the lead — opportunity details, what was said, or what they need."}]},{"heading":"Lead Statuses","items":[{"label":"New","value":"The starting stage for a new lead. Nobody has reached out yet. Shown as a blue label."},{"label":"Contacted","value":"You've reached out and the prospect knows who you are and what you offer. Shown as a teal label."},{"label":"Quoting","value":"You're preparing or have sent a quote or estimate. Shown as a yellow label."},{"label":"Converted","value":"The lead became a customer. Shown as a green label with a check. This is set for you by converting — you can't pick it by hand."},{"label":"Lost","value":"The deal didn't work out. You can record a reason, and you can reopen it back to New later. Shown as a gray label."}]},{"heading":"Table Columns","items":[{"label":"Company","value":"The company name, shown in bold. Click the heading to sort."},{"label":"Contact","value":"The contact person. Shows a dash when empty. Click the heading to sort."},{"label":"Source","value":"How the lead found you. Shows a dash when empty. Click the heading to sort."},{"label":"Status","value":"The lead's stage, shown as a colored label: New (blue), Contacted (teal), Quoting (yellow), Converted (green), Lost (gray). You can sort and filter by it."},{"label":"Follow-Up","value":"The follow-up date. Turns red when overdue, shows a dash when not set. Click the heading to sort."},{"label":"Created","value":"When the lead was created. Click the heading to sort."}]},{"heading":"Buttons and Actions","items":[{"label":"New Lead","value":"Opens the panel to add a new lead. Found in the page header."},{"label":"Table view","value":"Switches to the sortable list view. Your choice is remembered."},{"label":"Pipeline view","value":"Switches to the board with a column for each stage. Your choice is remembered."},{"label":"Save / Create Lead","value":"Saves the lead. Stays disabled while the form has a problem or a save is in progress. Hover it to see what still needs attention."},{"label":"Cancel","value":"Closes the panel without saving."},{"label":"Edit","value":"Opens the lead for editing, already filled in with its current values."},{"label":"Close","value":"Closes the lead panel."},{"label":"Status buttons","value":"Quick buttons to move the lead to New, Contacted, Quoting, or Lost from the lead panel. Hidden once the lead is Converted or Lost."},{"label":"Convert to Customer","value":"One click turns the lead into a customer and marks it Converted, then takes you to the new customer's page. There's no extra confirmation. Only available while the lead is still open."},{"label":"Conversion does not create a job","value":"There's no separate 'Convert + Create Job' choice. Converting only creates the customer; jobs come later from that customer's quotes and orders. Credit, tax, and address details are added on the customer page afterward."},{"label":"Reopen Lead","value":"Resets a Lost lead back to New. Only shows while the lead is Lost."},{"label":"Confirm Lost","value":"Marks the lead as Lost. You have to type a reason first — the button stays disabled until you do."},{"label":"Row click","value":"Opens the lead, showing all its fields, status buttons, convert options, and its activity history."},{"label":"Pipeline card drag","value":"Drag a card between columns on the board to change its stage. Dropping it on Lost asks you for a reason."}]},{"heading":"Validation Rules","items":[{"label":"Company Name","value":"Required. Can't be left blank."},{"label":"Email","value":"Optional, but if you fill it in it must look like a real email address."},{"label":"All other fields","value":"Optional. No special format needed."},{"label":"Save button hint","value":"When something's missing, hover the Save button to see what needs attention — for example 'Company Name is required'."},{"label":"Can't convert twice","value":"You can't convert a lead that's already Converted or Lost. Reopen a Lost lead first."}]},{"heading":"Lead Panel Sections","items":[{"label":"Header","value":"The company name in bold, the contact underneath, and buttons to edit or close."},{"label":"Info grid","value":"Status, email, phone, source, follow-up date (red if overdue), and the lost reason if lost. Empty fields are hidden."},{"label":"Notes","value":"Shows the lead's notes. Hidden when there are none."},{"label":"Status buttons","value":"A row of buttons for quick stage changes. Hidden once Converted or Lost."},{"label":"Convert","value":"A single Convert to Customer button. Hidden once Converted or Lost."},{"label":"Converted confirmation","value":"A green check with a confirmation message. Shows only after the lead is Converted."},{"label":"Reopen","value":"A Reopen Lead button. Shows only while the lead is Lost."},{"label":"Activity history","value":"A running timeline for the lead — stage changes, edits, notes, and conversion, newest first."}]},{"heading":"Pipeline Board Details","items":[{"label":"Columns","value":"Five columns: New, Contacted, Quoting, Converted, Lost. The Converted and Lost columns are dimmed."},{"label":"Column header","value":"The stage name and a count of how many leads are in it."},{"label":"Card content","value":"The company name in bold, the contact with their initials, the source, and the follow-up date (red if overdue)."},{"label":"Empty column","value":"Shows a 'No leads' message."},{"label":"Drag-and-drop","value":"Drag cards between any columns to change a lead's stage. Dropping on Lost asks you for a reason."}]}]}"""
