            AppRoutes = """["/leads"]""",
            Tags = """["leads","sales","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ld1","text":"A potential customer called asking about your machining services. What is the first step to track this opportunity?","options":[{"id":"a","text":"Create a Customer record in the Customers module"},{"id":"b","text":"Navigate to Leads, click New Lead, and enter the company name, contact info, and source","isCorrect":true},{"id":"c","text":"Create a Quote in the Quotes module with their company name"},{"id":"d","text":"Add a Job to the Kanban Board tagged as a prospect"}],"explanation":"New sales opportunities start as Leads. Click New Lead, fill in the company name (required), contact name, email, phone, and source. The lead starts in New status. Don't create a Customer record until the lead is qualified and ready for conversion."},{"id":"ld2","text":"You've sent an email introduction to a new lead. What status should the lead be in now?","options":[{"id":"a","text":"New — the lead hasn't responded yet"},{"id":"b","text":"Contacted — you've reached out to the prospect","isCorrect":true},{"id":"c","text":"Quoting — any communication counts as quoting"},{"id":"d","text":"Converted — the lead knows about your company now"}],"explanation":"Contacted means you've reached out to the prospect. They are aware of your company. Move to Quoting only when you're actually preparing or have sent a price quote or estimate."},{"id":"ld3","text":"What is the difference between the Quoting and Converted lead statuses?","options":[{"id":"a","text":"Quoting means a quote was sent; Converted means the quote was accepted"},{"id":"b","text":"Quoting means you're preparing or have sent a quote; Converted means the lead has been turned into a Customer record","isCorrect":true},{"id":"c","text":"They are the same — Converted is just the final stage of Quoting"},{"id":"d","text":"Quoting is for estimates only; Converted is for formal quotes"}],"explanation":"Quoting indicates a quote or estimate is in progress. Converted is a terminal status that means the lead has been turned into a Customer record via the Convert action. These are distinct pipeline stages."},{"id":"ld4","text":"A qualified lead is ready to become a customer. How do you convert it?","options":[{"id":"a","text":"Open the lead and click the single Convert to Customer button — one click creates the customer and marks the lead Converted","isCorrect":true},{"id":"b","text":"Step through a multi-step convert panel, entering credit, tax, and address details before it saves"},{"id":"c","text":"Choose between two buttons — Convert to Customer, or Convert to Customer + Create Job"},{"id":"d","text":"Create the customer record manually first, then link the lead to it"}],"explanation":"Converting is one click. The Convert to Customer button in the lead panel creates the customer from the lead's details and marks the lead Converted, then takes you to the new customer's page. It doesn't create a job and there's no multi-step panel — credit, tax, and address details are filled in afterward on the customer page."},{"id":"ld5","text":"A lead's follow-up date is showing in red in the table. What does this mean?","options":[{"id":"a","text":"The lead is marked as high priority"},{"id":"b","text":"The follow-up date has passed and the lead hasn't been updated — it's overdue","isCorrect":true},{"id":"c","text":"The lead is about to be automatically archived"},{"id":"d","text":"Someone else is currently working on this lead"}],"explanation":"A red follow-up date means the date has passed (overdue). This is a visual reminder that you need to follow up with the prospect. The lead won't be automatically changed — it's just a visual indicator."},{"id":"ld6","text":"You lost a deal to a competitor. How do you record this?","options":[{"id":"a","text":"Delete the lead from the system"},{"id":"b","text":"Change the status to Lost — a panel appears where you can enter the reason (e.g., 'Competitor won on price')","isCorrect":true},{"id":"c","text":"Archive the lead by clicking the archive button"},{"id":"d","text":"Move the lead to the Converted column and add a note saying it was lost"}],"explanation":"Click the Lost status button or drag the card to the Lost column. A panel appears asking for the lost reason, which is required — you can't confirm without entering one. The reason is stored for analysis. Lost leads can be reopened later if circumstances change."},{"id":"ld7","text":"A lead you marked as Lost six months ago has come back with renewed interest. What do you do?","options":[{"id":"a","text":"Create a new lead — lost leads cannot be reused"},{"id":"b","text":"Open the lead detail, click the Reopen Lead button to reset it to New status","isCorrect":true},{"id":"c","text":"Change the status directly to Contacted by editing the lead"},{"id":"d","text":"Convert the lost lead directly to a customer"}],"explanation":"Lost leads can be reopened. Open the lead and click the 'Reopen Lead' button. This resets the status to New so you can work the opportunity again. You cannot convert a Lost lead directly — you must reopen it first."},{"id":"ld8","text":"In Pipeline View, you drag a lead card from the Contacted column to the Lost column. What happens?","options":[{"id":"a","text":"The status changes to Lost immediately with no further action"},{"id":"b","text":"The card moves right away, and a panel appears asking for the lost reason","isCorrect":true},{"id":"c","text":"The drag is rejected — you can only mark leads as Lost from the detail panel"},{"id":"d","text":"The lead is permanently deleted from the system"}],"explanation":"Dragging a card to the Lost column brings up the lost reason panel. The card moves right away, and you must enter a reason for losing the deal. The reason is required — the Confirm button stays disabled until you fill it in."},{"id":"ld9","text":"Where do the choices in the Source menu come from?","options":[{"id":"a","text":"They are hardcoded in the application and cannot be changed"},{"id":"b","text":"They come from the admin settings and can be configured by admins","isCorrect":true},{"id":"c","text":"Each user creates their own source list in their profile settings"},{"id":"d","text":"They are imported from your email client automatically"}],"explanation":"Lead sources are managed in the admin settings. Admins can add, rename, or remove sources anytime. This keeps tracking consistent across the team."},{"id":"ld10","text":"When you convert a lead that has a Contact Name of 'Jane Smith', what happens to that contact information?","options":[{"id":"a","text":"Only the company name is used — contact details must be re-entered on the Customer record"},{"id":"b","text":"A Contact record is created on the new Customer with first name 'Jane', last name 'Smith', marked as primary, with the lead's email and phone","isCorrect":true},{"id":"c","text":"The contact name is stored in the Customer's notes field"},{"id":"d","text":"A separate user account is created for Jane Smith"}],"explanation":"When you convert a lead that has a contact name, a contact is created on the new customer for you. The name is split at the first space (first: 'Jane', last: 'Smith'), the contact carries over the lead's email and phone, and it's marked as the primary contact — so you don't have to re-enter any of it."},{"id":"ld11","text":"You want to see only leads that are in the Quoting stage. What is the fastest way?","options":[{"id":"a","text":"Switch to Pipeline View — the Quoting column shows exactly those leads","isCorrect":true},{"id":"b","text":"Export all leads to a spreadsheet and filter there"},{"id":"c","text":"Use the search box to type 'Quoting'"},{"id":"d","text":"Go to Reports and run a leads-by-status report"}],"explanation":"The Pipeline View organizes leads by status columns, so the Quoting column shows exactly what you need at a glance. Alternatively, in Table View you can use the Status filter menu to select Quoting. Both work, but Pipeline View gives you the visual overview."},{"id":"ld12","text":"What validation must pass before you can save a new lead?","options":[{"id":"a","text":"Company Name, Contact Name, and Email are all required"},{"id":"b","text":"Only Company Name is required — all other fields are optional","isCorrect":true},{"id":"c","text":"Company Name and Source are required"},{"id":"d","text":"All fields are optional — you can save a completely blank lead"}],"explanation":"Company Name is the only required field. Contact Name, Email, Phone, Source, Follow-Up Date, and Notes are all optional. If you fill in an email, it must look like a real email address. When something's missing, hover the Save button to see which fields need attention."}]}"""
