            SortOrder = 6,
            AppRoutes = """["/leads/intake"]""",
            Tags = """["leads","intake","import","walkthrough"]""",
            ContentJson = """{"appRoute":"/leads/intake","startButtonLabel":"Tour Bulk Intake","steps":[{"element":".intake__step:nth-of-type(1)","popover":{"title":"Step 1 — Pick How You Got Them","description":"Choose where this batch came from: cold call, cold email, trade show follow-up, webinar attendee, purchased list, or manual entry. Your choice sets which fields are required — cold calls need a phone, cold emails need an email. You can also add a campaign tag to group the batch for reporting.","side":"bottom"}},{"element":".intake__columns-help","popover":{"title":"Which Columns to Include","description":"Only the company name is required. Contact, email, phone, source, and notes are optional. Column headings don't have to match exactly — common names are accepted. Open this reference any time you're unsure of the format.","side":"top"}},{"element":".intake__upload-button","popover":{"title":"Upload a Spreadsheet File","description":"Click here to pick a CSV file from your computer. The first row must name the columns. Once the file is read, its rows appear below for review.","side":"bottom"}},{"element":".intake__upload + app-textarea","popover":{"title":"Or Paste Rows","description":"Instead of a file, paste rows straight in — handy for a quick list copied from a spreadsheet. The first line must name the columns.","side":"top"}},{"element":"[data-testid='intake-parse-paste']","popover":{"title":"Read the Pasted Rows","description":"After pasting, click to read the rows into the preview below. Any rows that couldn't be read are listed so you can fix them.","side":"top"}},{"element":"[data-testid='intake-preview-btn']","popover":{"title":"Preview and Check for Duplicates","description":"Run the preview. Each row is checked against your existing leads and customers, anyone who opted out, anyone still in a wait period, and duplicates within the batch. Every row is then labeled — will create, duplicate, opted out, in wait period, or missing a required field. Nothing is added yet.","side":"top"}},{"element":"[data-testid='intake-commit-btn']","popover":{"title":"Add the Good Rows","description":"Review the label on each row, then add them. Only rows marked \"will create\" are added — duplicates, opt-outs, and wait periods are skipped for you. A summary shows how many were added versus skipped, then you're taken back to the leads list.","side":"top"}}]}"""
        });

